#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $log_dir = '/path/to/log/directory';
my $query = CGI->new;
my $filename = $query->param('logfile');

print $query->header(-type => 'text/plain');

if ($filename && $filename =~ /^[a-zA-Z0-9._-]+$/) {
    my $file_path = "$log_dir/$filename";
    if (open(FH, "<", $file_path)) {
        while (my $line = <FH>) {
            print $line;
        }
        close(FH);
    } else {
        print "Error: Unable to open file $file_path\n";
    }
} else {
    print "Error: Invalid or missing logfile parameter\n";
}